--- a/BCAzureStreamAnalytics/src/Test/ProductAnalyticsTests.Codeunit.al+++ b/BCAzureStreamAnalytics/src/Test/ProductAnalyticsTests.Codeunit.al@@ -19,6 +19,31 @@             Error('Expected empty JSON array but got: %1', JsonResult);
