+    [Test]
+    procedure T002_BuildProductAnalyticsJsonIncludesBlockedProducts()
+    var
+        ProductAnalyticsLookup: Record "Product Analytics Lookup";
+        ProductAnalyticsHelper: Codeunit "Product Analytics Helper";
+        Assert: Codeunit Assert;
+        JsonResult: Text;
+    begin
+        // [SCENARIO #002] BuildProductAnalyticsJson must include blocked products in the export
+        DeleteAllProductAnalyticsData();
+
+        // [GIVEN] A blocked Product Analytics record exists
+        ProductAnalyticsLookup.Init();
+        ProductAnalyticsLookup."Product No." := 'TESTBLK001';
+        ProductAnalyticsLookup."Product Name" := 'Blocked Test Product';
+        ProductAnalyticsLookup.Blocked := true;
+        ProductAnalyticsLookup.Insert();
+
+        // [WHEN] BuildProductAnalyticsJson is called
+        JsonResult := ProductAnalyticsHelper.BuildProductAnalyticsJson();
+
+        // [THEN] Result is not an empty array (blocked product was included)
+        Assert.AreNotEqual('[]', JsonResult, 'BuildProductAnalyticsJson must include blocked products.');
+    end;
+
     local procedure DeleteAllProductAnalyticsData()
     var
         ProductAnalyticsLookup: Record "Product Analytics Lookup";

